function waterfall(container) {
    const getMargin = (side, element) => {
        const computedStyle = window.getComputedStyle(element);
        return parseFloat(computedStyle["margin" + side]) || 0;
    };

    const px = (value) => {
        return value + "px";
    };

    const getTop = (element) => {
        return parseFloat(element.style.top);
    };

    const getLeft = (element) => {
        return parseFloat(element.style.left);
    };

    const getWidth = (element) => {
        return element.clientWidth;
    };

    const getHeight = (element) => {
        return element.clientHeight;
    };

    const getBottom = (element) => {
        return getTop(element) + getHeight(element) + getMargin("Bottom", element);
    };

    const getRight = (element) => {
        return getLeft(element) + getWidth(element) + getMargin("Right", element);
    };

    const sortElements = (elements) => {
        elements.sort((a, b) => {
            return getBottom(a) === getBottom(b) ? getLeft(b) - getLeft(a) : getBottom(b) - getBottom(a);
        });
    };

    const handleResize = (event) => {
        if (getWidth(container) !== containerWidth) {
            window.removeEventListener(event.type, handleResize);
            waterfall(container);
        }
    };

    if (typeof container === "string") {
        container = document.querySelector(container);
    }

    const elements = Array.from(container.children).map((element) => {
        element.style.position = "absolute";
        return element;
    });

    container.style.position = "relative";

    const sortedElements = [];
    if (elements.length > 0) {
        elements[0].style.top = "0px";
        elements[0].style.left = px(getMargin("Left", elements[0]));
        sortedElements.push(elements[0]);
    }

    let i;
    for (i = 1; i < elements.length; i++) {
        const previousElement = elements[i - 1];
        const currentElement = elements[i];
        const canFit = getRight(previousElement) + getWidth(currentElement) <= getWidth(container);
        if (!canFit) {
            break;
        }
        currentElement.style.top = previousElement.style.top;
        currentElement.style.left = px(getRight(previousElement) + getMargin("Left", currentElement));
        sortedElements.push(currentElement);
    }

    for (; i < elements.length; i++) {
        sortElements(sortedElements);
        const currentElement = elements[i];
        const lastElement = sortedElements.pop();
        currentElement.style.top = px(getBottom(lastElement) + getMargin("Top", currentElement));
        currentElement.style.left = px(getLeft(lastElement));
        sortedElements.push(currentElement);
    }

    sortElements(sortedElements);
    const firstElement = sortedElements[0];
    container.style.height = px(getBottom(firstElement) + getMargin("Bottom", firstElement));
    const containerWidth = getWidth(container);

    if (window.addEventListener) {
        window.addEventListener("resize", handleResize);
    } else {
        document.body.onresize = handleResize;
    }
}

// 瀑布流处理